/* eslint-disable no-restricted-globals */

import { getArgsFromUrl } from '@badam/common-utils'

/* eslint-disable import/prefer-default-export */
const targetVersoin = 1291

export function isTargetVersion() {
  try {
    const vv = getArgsFromUrl('version_code')
    const vvv = Object.prototype.toString.call(vv) === '[object Array]' ? vv[0] : vv
    const v = vvv.split('.').join('')
    const version = parseInt(v, 10)
    return version >= targetVersoin
  } catch (e) {
    return false
  }
}

type Params = {
  login_type: 'facebook' | 'google' | 'apple'
  user_id?: string // facebook、apple必填
  access_token?: string // facebook、apple必填
  id_token?: string // google必填
}

export function callbackToClient(p: Params) {
  const ticket = encodeURIComponent(JSON.stringify(p))
  location.href = `sawaludo://sawaksa_login_key?ticket=${ticket}`
}

export function goToMobileWebview() {
  location.hash = 'mobile'
  try {
    location.href = `sawaludo://sawaksa_login_mobile?url=${encodeURIComponent(location.href)}`
  } catch (e) {
    //
  }
  location.hash = ''
}
